function useInView(t=0.12){const r=useRef();const[v,setV]=useState(false);useEffect(()=>{const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)setV(true)},{threshold:t});if(r.current)o.observe(r.current);return()=>o.disconnect();},[]);return[r,v];}
function useCounter(end,active){const[val,setVal]=useState(0);useEffect(()=>{if(!active)return;let t=null,s=null;const step=(ts)=>{if(!s)s=ts;const p=Math.min((ts-s)/1200,1);setVal(Math.floor(p*end));if(p<1)t=requestAnimationFrame(step);else setVal(end);};t=requestAnimationFrame(step);return()=>cancelAnimationFrame(t);},[active,end]);return val;}

